mapper.select:
SELECT keyword, total_count as count, confidence_score as confidence, segment_name as segment, member_count, workplace_count FROM keyword_segments WHERE segment_type = #{segmentType}
AND segment_name = #{segmentName}
ORDER BY total_count DESC, confidence_score DESC LIMIT #{limit}

SELECT COUNT(*)
FROM keyword_segments
WHERE segment_type = #{segmentType}
  AND segment_name = #{segmentName}

SELECT keyword, segment_type, segment_name, total_count as count, confidence_score as confidence, member_count, workplace_count FROM keyword_segments WHERE keyword LIKE CONCAT('%', #{searchTerm}, '%')
AND segment_type = #{segmentType}
AND segment_name = #{segmentName}
ORDER BY total_count DESC, confidence_score DESC LIMIT #{limit}

WITH segment_keywords AS ( SELECT DISTINCT keyword FROM keyword_segments WHERE segment_type = #{segmentType}
AND segment_name = #{segmentName}
) SELECT krs.keyword1, krs.keyword2, krs.relationship_strength as strength, krs.co_occurrence_count as co_occurrence, krs.pmi_score FROM keyword_relationships_summary krs WHERE (krs.keyword1 IN (SELECT keyword FROM segment_keywords) OR krs.keyword2 IN (SELECT keyword FROM segment_keywords)) AND krs.segment_filter = 'all' ORDER BY krs.relationship_strength DESC LIMIT #{limit}
